    outp += (j - i);
    i = j;
}
Console.WriteLine(outp);
```

answer_code:
using System;

class Program {
    static void Main() {
        string s = Console.ReadLine();
        string outp = "";
        int i = 0;
        while (i < s.Length) {
            int j = i;
            while (j < s.Length && s[j] == s[i]) j++;
            outp += s[i];
            outp += (j - i);
            i = j;
        }
        Console.WriteLine(outp);
    }
}
